using ModelContextProtocol.Server;
using System.ComponentModel;

namespace McpWebServer.Tools;

[McpServerToolType]
public static class EchoTools
{
    [McpServerTool, Description("Echoes the provided message back to the caller.")]
    public static string Echo(
        [Description("The message to echo back")] string message)
    {
        return $"Echo: {message}";
    }

    [McpServerTool, Description("Returns the current server time in UTC.")]
    public static string GetServerTime()
    {
        return DateTime.UtcNow.ToString("o");
    }
}

using ModelContextProtocol.Server;
using System.ComponentModel;
using System.Text.Json;

namespace McpWebServer.Resources;

[McpServerResourceType]
public static class ConfigResources
{
    [McpServerResource(
        UriTemplate = "config://app",
        Name = "App Configuration",
        MimeType = "application/json"),
     Description("Returns the current application configuration.")]
    public static string GetAppConfig()
    {
        var config = new
        {
            AppName = "McpWebServer",
            Version = "1.0.0",
            Environment = Environment.GetEnvironmentVariable("ASPNETCORE_ENVIRONMENT") ?? "Production",
            MaxConnections = 100,
            Features = new { Logging = true, Caching = true, Telemetry = false }
        };

        return JsonSerializer.Serialize(config, new JsonSerializerOptions { WriteIndented = true });
    }

    [McpServerResource(
        UriTemplate = "config://endpoints",
        Name = "API Endpoints",
        MimeType = "application/json"),
     Description("Lists available API endpoints and their descriptions.")]
    public static string GetEndpoints()
    {
        var endpoints = new[]
        {
            new { Path = "/mcp", Method = "POST", Description = "MCP Streamable HTTP endpoint" },
            new { Path = "/health", Method = "GET", Description = "Health check" }
        };

        return JsonSerializer.Serialize(endpoints, new JsonSerializerOptions { WriteIndented = true });
    }
}

